const raw = $('Outreach Webhook').first().json;
const input = raw && raw.body && typeof raw.body === 'object' && !Array.isArray(raw.body) ? raw.body : raw;
const config = $('Get Config').first().json;

return [{
  json: {
    contactId: input.contactId || input.contact_id || '',
    company: input.company || '',
    industry: input.industry || '',
    firstName: input.firstName || input.firstname || '',
    config: config
  }
}];

const data = $('Prepare Sequence Data').first().json;

return [{
  json: {
    to: data.config.owner.email,
    subject: `Quick question about ${data.company}'s operations`,
    html: `<p>Hi ${data.firstName || 'there'},</p><p>I came across ${data.company} and wanted to reach out. We help ${data.industry || 'businesses'} like yours automate operations — everything from lead follow-up to invoicing to client onboarding.</p><p>Most of our clients save 15-20 hours per week once their systems are running.</p><p>Worth a 15-minute conversation to see if there's a fit?</p><p>— John<br/>IntraWeb Technologies</p>`,
    workflowName: 'SYS 02 — Outbound Lead Outreach Sequence'
  }
}];

const data = $('Prepare Sequence Data').first().json;

return [{
  json: {
    workflowName: 'SYS 02 — Outbound Lead Outreach Sequence',
    contactName: data.firstName,
    phone: '',
    eventType: 'email_sent',
    status: 'success',
    notes: 'Touch 1: Initial outreach email'
  }
}];

const data = $('Prepare Sequence Data').first().json;

return [{
  json: {
    to: data.config.owner.phone,
